/**
 * SEO Component - Multilingual SEO with hreflang
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import Head from 'next/head';

interface SEOProps {
  title: string;
  description: string;
  language: string;
  slug: string;
  image?: string;
  type?: 'website' | 'article';
  publishedTime?: string;
  modifiedTime?: string;
}

const SITE_URL = process.env.NEXT_PUBLIC_BASE_URL || 'https://ivaflow.com';

const SUPPORTED_LANGUAGES = ['en', 'ar', 'tr', 'fr', 'de', 'es'];

export function SEO({
  title,
  description,
  language,
  slug,
  image,
  type = 'website',
  publishedTime,
  modifiedTime
}: SEOProps) {
  const fullTitle = `${title} | IVAFlow`;
  const canonicalUrl = `${SITE_URL}/${language}/${slug}`;
  const defaultImage = `${SITE_URL}/og-image.png`;
  const ogImage = image || defaultImage;

  return (
    <Head>
      {/* Basic Meta Tags */}
      <title>{fullTitle}</title>
      <meta name="description" content={description} />
      <meta name="language" content={language} />
      
      {/* Canonical URL */}
      <link rel="canonical" href={canonicalUrl} />
      
      {/* Hreflang Tags for Multilingual SEO */}
      {SUPPORTED_LANGUAGES.map(lang => (
        <link
          key={lang}
          rel="alternate"
          hrefLang={lang}
          href={`${SITE_URL}/${lang}/${slug}`}
        />
      ))}
      <link rel="alternate" hrefLang="x-default" href={`${SITE_URL}/en/${slug}`} />
      
      {/* Open Graph Meta Tags */}
      <meta property="og:type" content={type} />
      <meta property="og:title" content={fullTitle} />
      <meta property="og:description" content={description} />
      <meta property="og:url" content={canonicalUrl} />
      <meta property="og:image" content={ogImage} />
      <meta property="og:locale" content={getLocale(language)} />
      {SUPPORTED_LANGUAGES.filter(l => l !== language).map(lang => (
        <meta key={lang} property="og:locale:alternate" content={getLocale(lang)} />
      ))}
      
      {/* Article Meta Tags */}
      {type === 'article' && publishedTime && (
        <meta property="article:published_time" content={publishedTime} />
      )}
      {type === 'article' && modifiedTime && (
        <meta property="article:modified_time" content={modifiedTime} />
      )}
      
      {/* Twitter Card Meta Tags */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={fullTitle} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={ogImage} />
      
      {/* Additional SEO Tags */}
      <meta name="robots" content="index, follow" />
      <meta name="googlebot" content="index, follow" />
    </Head>
  );
}

function getLocale(language: string): string {
  const localeMap: Record<string, string> = {
    en: 'en_US',
    ar: 'ar_SA',
    tr: 'tr_TR',
    fr: 'fr_FR',
    de: 'de_DE',
    es: 'es_ES'
  };
  return localeMap[language] || 'en_US';
}
